function addImageToPdf(pdf, img,imgSrc,canvasId, w,h, x, y) {
    img.src = imgSrc;
    $("body").append('<canvas id="' + canvasId + '" width="' + w + '" height="' + h + '" style="visibility:hidden"></canvas>');
    var canvasEl = $("#" + canvasId)[0];
    var ctx = canvasEl.getContext("2d");
    
    ctx.drawImage(img, 0, 0);
    var dataURL = canvasEl.toDataURL("image/png");
    pdf.addImage(img, x, y, w, h);
    
}

function drowHeader(pdf, x, y, text) {
    pdf.setTextColor(0);
    pdf.setFontSize(14);
    pdf.setDrawColor(100);
    var textMargin = 4;
    var textWidth = text.length * 2.5;
    var headerWidth = 210 - x * 2;
    var lineWidth = (headerWidth - textWidth - 2 * textMargin) / 2;
    pdf.line(x, y, x + lineWidth, y,'FD');
    pdf.text(text, x + lineWidth + textMargin,y+2);
    pdf.line(x + lineWidth + textMargin * 2 + textWidth, y, x + lineWidth*2 + textMargin * 2 + textWidth,y,'FD')

}
function drawGrid(x, y, w, h, col, row, gapx,gapy) {
    var gridArray = [];
    var cellWidth = (w - ((col - 1) * gapx)) / col;
    var cellHeight = (h - ((row - 1) * gapy)) / row;
    for (var i = 0; i < col; i++) {
       
        for (var j = 0; j < row; j++) {
            var cellX = x + i * (cellWidth+gapx);
            var cellY = y + j * (cellHeight + gapy);
            gridArray.push({ x: cellX, y: cellY, w: cellWidth, h: cellHeight });
        }
        
    }
    return gridArray;
}
function drawLegend(pdf,x,y,w,colors,textArray) {
    var legendGrid = drawGrid(x, y, w, 10, 3, 1, 5, 1);
    for (var i = 0; i < legendGrid.length; i++) {
        var x = legendGrid[i].x;
        var y = legendGrid[i].y;
        var w = legendGrid[i].w;
        var h = legendGrid[i].h;
        var color = colors[i];
        var title = textArray[i];
        console.log("x, y, color, title", x, y, color, title);
        pdf.setFontSize(10);
        pdf.setTextColor(100);
        pdf.setFillColor(color);
        pdf.setDrawColor("#ddd");
        pdf.circle(x + 1, y + 1, 2,'FD');
        pdf.text(title, x + 5, y + 3);


    }
}
function wrapPdfText(pdf, text, x, y, words,lineHeight) {
     
    var textArray = text.split(" ");
    var arrayCount = textArray.length;
    var lineCount = parseInt(arrayCount / words);
    if (arrayCount > words) {
        var textHeight = lineCount * lineHeight;
        y = y - textHeight / 2;
    }
   
    var line = "";
    var lineCounter = 0;
    
    if (textArray.length > words) {
        for (var i = 0; i < textArray.length; i++) {
            line += textArray[i] + " ";
            if (i % words == 0 && i != 0) {
                pdf.text(line, x, y);
                lineCounter++;
                y += lineHeight;
                line = "";
            }
            
        }
        
        pdf.text(line, x, y);
        
        
    } else {
        pdf.text(text, x, y);
    }
}
function drawBarChart(pdf, dir,  y, chartArray, colors, rowGap, colCount, words, lineHeigth,stripOffset) {
    if (chartArray.length != 0) {
        pdf.setDrawColor(255);
        var stripColor = 240;
        var barCount = chartArray.length;
        var is_material_chart = false;
        var material_code = "";
        if (dir == "h") {
            var w = 190;
            var x = (210 - w) / 2;
        } else {
            rowGap = 80 / barCount;
            var w = 40;
            var wv = barCount * 5 + ((barCount - 2) * rowGap);
            var x = (210 - wv) / 2;
        }

        if (chartArray[0][2] != undefined) {
          
            is_material_chart = true;
        } else {
            is_material_chart = false;
        }
        if (!$.isArray(chartArray[0][1])) {
            for (var i = 0; i < chartArray.length; i++) {
                var rowVal = chartArray[i][1];
                var rowValArr = [["type", rowVal]];
                chartArray[i][1] = rowValArr;
            }
        }
        
        pdf.setTextColor(40);
        pdf.setFontSize(8);
        if (dir == "h") {
            var barValueWidth = 15;
            var titleWidth = (w - barValueWidth) / colCount;
            var barWidth = (w - barValueWidth) * (colCount - 1) / colCount;
            var maxValue = 0;
            var barChartArray = [];
            var barX = x + titleWidth;
            var barY = y;
            var valueX = w - barValueWidth;
            var valueY = y;
            var valueArray = [];
            if (chartArray) {
                for (var i = 0; i < chartArray.length; i++) {
                    var rowData = [];
                    var barTitle = chartArray[i][0];
                   
                    material_code = is_material_chart ? chartArray[i][2] : "";
                    var barData = chartArray[i][1];
                    var rowTotal = 0;
                    var newY = y + i * rowGap;
                    pdf.setFillColor(stripColor);
                    if (i % 2 == 0) {
                        pdf.rect(x - 2, newY - (rowGap / 4) - stripOffset, w, rowGap + stripOffset, 'FD');
                    }
                    for (var k = 0; k < barData.length; k++) {
                        var dataType = barData[k][0];
                        var typeValue = barData[k][1];
                        rowData.push({ type: dataType, value: typeValue });
                        if (i == 0) {
                            maxValue += parseFloat(typeValue);
                        }
                        rowTotal += parseFloat(typeValue);
                    }
                    var oneRowData = { rowTitle: barTitle, rowTotal: rowTotal, rowData: rowData, code:material_code };
                    barChartArray.push(oneRowData);
                }
                maxValue += maxValue * 0.1;
                var ratio = barWidth / maxValue;
                pdf.setFontStyle("normal");
                var textOffset = 3;
                for (var i = 0; i < barChartArray.length; i++) {
                    var partialBarX = barX;
                    var rowTitle = barChartArray[i].rowTitle;
                    var rowTotal = barChartArray[i].rowTotal;
                    var rowData = barChartArray[i].rowData;
                    var row_code = barChartArray[i].code;
                    rowData.reverse();
                    var newY = y + i * rowGap;
                    wrapPdfText(pdf, "" + (is_material_chart ? row_code + " :" : "") + rowTitle, x, newY + textOffset, words, lineHeigth);

                    for (var k = 0; k < rowData.length; k++) {
                        var partialBarVal = parseFloat(rowData[k].value);
                        var partialBarW = partialBarVal * ratio;
                        pdf.setFillColor(colors[k]);

                        pdf.rect(partialBarX, newY, partialBarW, 5, 'FD');

                        partialBarX += partialBarW;
                    }
                    wrapPdfText(pdf, "" + Math.ceil(rowTotal * 10) / 10, partialBarX + 2, newY + textOffset, words, lineHeigth);
                }
            }
        } else if (dir == "v") {
            //direction is vertically
            var totals = [];
            colors.reverse();
            var barValueHeight = 10;
            var titleHeight = (w - barValueHeight) / colCount;
            var barHeight = (w - barValueHeight) * (colCount - 1) / colCount;
            var maxValue = 0;
            var barChartArray = [];
            var barX = x;
            var startY = y + w;
            var barY = startY - barValueHeight;
            if (chartArray) {
                for (var i = 0; i < chartArray.length; i++) {
                    var rowData = [];
                    var barTitle = chartArray[i][0];
                    var barData = chartArray[i][1];
                    var rowTotal = 0;

                    for (var k = 0; k < barData.length; k++) {
                        var dataType = barData[k][0];
                        var typeValue = Math.abs(barData[k][1]);
                        rowData.push({ type: dataType, value: typeValue });
                        //if (i == 0) {
                        //    maxValue += parseFloat(typeValue);
                        //}
                        rowTotal += parseFloat(typeValue);

                    }
                    var oneRowData = { rowTitle: barTitle, rowTotal: rowTotal, rowData: rowData };
                    barChartArray.push(oneRowData);
                    totals.push(rowTotal);
                }
                maxValue = Math.max.apply(Math, totals);
                maxValue += maxValue * 0.1;
                var ratio = barHeight / maxValue;
                console.log(maxValue, ratio);
                pdf.setFontStyle("normal");
                var textOffset = 3;
                for (var i = 0; i < barChartArray.length; i++) {
                    var partialBarY = barY;
                    var rowTitle = barChartArray[i].rowTitle;
                    var rowTotal = barChartArray[i].rowTotal;
                    var rowData = barChartArray[i].rowData;
                    //rowData.reverse();
                    var newX = x + i * (rowGap + 5);
                    pdf.setFillColor(stripColor);

                    if (i % 2 == 0) {
                        pdf.rect(newX - (rowGap / 2), y - 2, rowGap + 5, w, 'FD');
                    }
                    for (var k = 0; k < rowData.length; k++) {
                        var partialBarVal = Math.abs(parseFloat(rowData[k].value));
                        var partialBarH = partialBarVal * ratio;
                        pdf.setFillColor(colors[k]);
                        partialBarY -= partialBarH;
                        pdf.rect(newX, partialBarY, 5, partialBarH, 'FD');
                    }

                    wrapPdfText(pdf, "" + Math.ceil(parseFloat(rowTotal) * 10) / 10, newX, partialBarY - 2, words, lineHeigth);
                    wrapPdfText(pdf, "" + rowTitle, newX, startY - 7 + textOffset, words, lineHeigth);
                }
            }
        } else if (dir == "vr") {
            pdf.setLineWidth(0);
            colors.reverse();
            var totals = [];
            var barValueHeight = 10;
            var titleHeight = (w - barValueHeight) / colCount;
            var barHeight = (w - barValueHeight) * (colCount - 1) / colCount;
            var maxValue = 0;
            var barChartArray = [];
            var barX = x;
            var startY = y + w;
            var negativeFlag = false;
            var barY = startY - barValueHeight;
            if (chartArray) {
                for (var i = 0; i < chartArray.length; i++) {
                    var rowData = [];
                    var barTitle = chartArray[i][0];
                    var barData = chartArray[i][1];
                    var rowTotal = 0;
                    for (var k = 0; k < barData.length; k++) {
                        var dataType = barData[k][0];
                        var typeValue = barData[k][1];
                        rowData.push({ type: dataType, value: typeValue });
                        if (typeValue < 0) {
                            negativeFlag = true;
                        }

                        rowTotal += parseFloat(typeValue);
                    }
                    var oneRowData = { rowTitle: barTitle, rowTotal: rowTotal, rowData: rowData };
                    barChartArray.push(oneRowData);
                    totals.push(rowTotal);
                }
                var positiveTotal = [];
                for (var z = 0; z < totals.length; z++) {
                    positiveTotal.push(Math.abs(totals[z]));
                }
                maxValue = Math.max.apply(Math, positiveTotal);
                maxValue += maxValue * 0.1;
                //alert(maxValue);
                var ratio = (barHeight / 2) / maxValue;

                pdf.setFontStyle("normal");
                var textOffset = 3;
                for (var i = 0; i < barChartArray.length; i++) {
                    var partialBarY = barY + barHeight / 2;
                    var standingPoint = partialBarY;
                    var rowTitle = barChartArray[i].rowTitle;
                    var rowTotal = barChartArray[i].rowTotal;
                    var rowData = barChartArray[i].rowData;
                    //rowData.reverse();
                    var newX = x + i * (rowGap + 5);
                    pdf.setFillColor(stripColor);
                    if (i % 2 == 0) {
                        pdf.rect(newX - (rowGap / 2), barY - 8, rowGap + 5, w, 'FD');
                    }
                    for (var k = 0; k < rowData.length; k++) {
                        var partialBarVal = parseFloat(rowData[k].value);
                        var partialBarH = partialBarVal * ratio * -1;
                        if (partialBarVal < 0) {
                            color = "#E87373";
                        } else {
                            color = "#1DD1A1";

                        }
                        pdf.setFillColor(color);

                        partialBarY += partialBarH;
                        if (partialBarY < standingPoint) {
                            partialBarY -= 5;
                        }
                        pdf.rect(newX, barY + barHeight / 2, 5, partialBarH, 'FD');
                    }
                    wrapPdfText(pdf, "" + rowTitle, newX - 1, barY + barHeight + 10, words, lineHeigth);
                    wrapPdfText(pdf, "" + Math.ceil(parseFloat(rowTotal) * 10) / 10, newX, partialBarY + textOffset, words, lineHeigth);
                }
            }

        }
    }
    
}
function drawLineChart(pdf, dir,  y,  chartArray, color, rowGap, colCount, words, lineHeigth, stripOffset) {
    if (chartArray.length != 0) {
        var barCount = chartArray.length;
        var w = 40;
        rowGap = 100 / barCount;
        var wv = barCount * 5 + ((barCount - 1) * rowGap);
        var x = (210 - wv) / 2;
        var stripColor = 230;
        if (!$.isArray(chartArray[0][1])) {
            for (var i = 0; i < chartArray.length; i++) {
                var rowVal = chartArray[i][1];
                var rowValArr = [["type", rowVal]];
                chartArray[i][1] = rowValArr;
            }
        }
        pdf.setTextColor(40);
        pdf.setFontSize(8);
    
        if (dir == "v") {
            //direction is vertically
            var totals = [];
            var barValueHeight = 10;
            var titleHeight = (w - barValueHeight) / colCount;
            var barHeight = (w - barValueHeight) * (colCount - 1) / colCount;
            var maxValue = 0;
            var barChartArray = [];
            var barX = x;
            var startY = y + w;
            var barY = startY - barValueHeight;
            if (chartArray) {
                for (var i = 0; i < chartArray.length; i++) {
                    var rowData = [];
                    var barTitle = chartArray[i][0];
                    var barData = chartArray[i][1];
                    var rowTotal = 0;
                    for (var k = 0; k < barData.length; k++) {
                        var dataType = barData[k][0];
                        var typeValue = barData[k][1];
                        rowData.push({ type: dataType, value: typeValue });
                        //if (i == 0) {
                        //    maxValue += Math.abs(parseFloat(typeValue));
                        //}
                        rowTotal += Math.abs(parseFloat(typeValue));
                    }
                    var oneRowData = { rowTitle: barTitle, rowTotal: rowTotal, rowData: rowData };
                    barChartArray.push(oneRowData);
                    totals.push(rowTotal);
                }
                maxValue = Math.max.apply(Math, totals);
                maxValue += maxValue * 0.1;
                var ratio = barHeight / (maxValue*3);
                pdf.setFontStyle("normal");
                var textOffset = 3;
           
                var prevX = 0;
                var prevVal = 0
            
                for (var i = 0; i < barChartArray.length; i++) {
                    pdf.setLineWidth(0);
                    var partialBarY = barY-barHeight/2;
                    var rowTitle = barChartArray[i].rowTitle;
                    var rowTotal = barChartArray[i].rowTotal;
                    var rowData = barChartArray[i].rowData;
                    //rowData.reverse();
                    var newX = x + i * (rowGap + 5);
                    pdf.setFillColor(stripColor);
                    pdf.setDrawColor(stripColor);
                    if (i % 2 == 0) {
                        pdf.rect(newX - (rowGap / 2), y - 2, rowGap + 5, w, 'FD');
                    }
                    pdf.setFillColor(color);
                    for (var k = 0; k < rowData.length; k++) {
                        var partialBarVal = parseFloat(rowData[k].value);
                        var partialBarH = partialBarVal * ratio;
                        partialBarY -= partialBarH;
                        pdf.circle(newX + 3, partialBarY, 1.5, 'FD');
                        if (prevVal != 0) {
                            pdf.setLineWidth(0.5);
                            pdf.setDrawColor(color);
                            pdf.line(prevX, prevVal, newX + 3, partialBarY, 'FD');
                        }
                        prevVal = partialBarY;
                        prevX = newX + 3;
                    }
                    pdf.setDrawColor(stripColor);
                    wrapPdfText(pdf, "" + Math.ceil(parseFloat(partialBarVal) * 10) /10 + "%", newX + 1, partialBarY - 5, words, lineHeigth);
                    wrapPdfText(pdf, "" + rowTitle, newX, startY - 7 + textOffset, words, lineHeigth);
                }
            }
        }
    }
    
}
function getFilter() {
    filterArray = [];
   var currency =  $("#currencyIn").val();
   var group = $("#groupIn").val();
   $('#currency option[value ="' + currency + '" ]').prop("selected",true);
   $('#slcgroup option[value ="' + group + '" ]').prop("selected",true);
   var filterCategoryStr =  $("#trcatIn").val();
   var filterContinentStr =  $("#continentIn").val();
   var filterCountryStr =  $("#countryIn").val();
   var filterTradeStr =  $("#trtypeIn").val();
   var filterSectionStr = $("#sectionIn").val();
   var filterChapterStr =  $("#chapterIn").val();
   var filterRegionStr =  $("#regionIn").val();
   var codeData =  $("#datacodeIn").val();
   filterArray.push(["currency", currency]);
   filterArray.push(["group", group]);
   filterArray.push(["trCat", filterCategoryStr]);
   filterArray.push(["contintent", filterContinentStr]);
   filterArray.push(["country", filterCountryStr]);
   filterArray.push(["tradeType", filterTradeStr]);
   filterArray.push(["section", filterSectionStr]);
   filterArray.push(["chapter", filterChapterStr]);
   filterArray.push(["region", filterRegionStr]);
    
   filterArray.push(["codeMaterial", codeData]);
   return filterArray;
}
function setValuesFormats(val) {
    var value = new Number(val);
    if (value == 0) return '0.0';
    if (value > 0) {
        if (value < 0.1) {
            return value.toPrecision(1);
        } if (value < 1) {
            return value.toFixed(2);
        } if (value < 1000) {
            return value.toFixed(1);
        } return value.toFixed(0);
    } else {
        if (value <= -1000)
            return value.toFixed(0);
        if (value <= -1) {
            return value.toFixed(0);
        } if (value <= -0.1) {
            return value.toFixed(1)
        } return value.toPrecision(1);
    }
}

