function drawBalanceChart(filterArray, colors) {
    
    balanceChartTable = '';
    balDataArray = [];
    dataTxt = $("#amount").text();
    dataArr = dataTxt.split(" - ");
    minYear = dataArr[0];
    maxYear = dataArr[1];
    var colors = [];
    var trTypeArr = ["Re-Exports", "Non-Oil Exports", "Imports"];
    var steps = 3;

    if (filterArray[0][0] != "init") {
        if (filterArray[5][1] != "ALL") {

            tradeTypes = filterArray[5][1];

            trTypeArrB = tradeTypes.split("|");

            steps = trTypeArrB.length;

        }
    }

    $(".tradeColorContainer").children(".trColor").each(function () {
        colors.push($(this).css("background-color"));
    });
   
   
    var subColumnArray = [];
    var tempYear = "";
    var yrSubColArr_new = [];
   
   
    var balColArray = [];
    var counter = 0;
    var wholeValue = 0;
    var wholeValueARR = [];
    var wholeVal = 0;
    var steps = 3;
    var balValueArray = [];
   
    balanceChartTable += '<table><tr><th>Year</th><th>Balance</th></tr>';
   
    data = { yearF: minYear, yearT: maxYear, filter: filterArray };
    $.ajax({
        type: "POST",
        url: "Server.aspx/GetDataYearsBalance",
        data: JSON.stringify(data),
        contentType: "application/json; charset=utf-8",
        dataType: "json",
        success: function (response) {
            var dataBYY = response.d;
            dataBYY.push({
                "__type": "tradingMap.dataGOTByCountry",
                "year": "noneCnt",
                "tradeType": "noneTrade",
                "value": "0"
            });
            $(dataBYY).each(function () {
                counter++;
                year = this.year;
                valueTrade = this.value;
                tradeType = this.tradeType;
                var oneBitArray = [tradeType, valueTrade];
                yrSubColArr_new.push(oneBitArray);
                wholeVal += Number(valueTrade);
                //new code for missing trade types

                if (tempYear != "" && tempYear != year) {
                    var lasSubColArray = [];
                    yrSubColArr_new.pop();
                    wholeVal -= Number(valueTrade);
                    wholeValueARR.push(wholeVal);
                    if (yrSubColArr_new.length < 3) {
                        var bitCounter = yrSubColArr_new.length;
                        var diff = 3 - bitCounter;
                        var lasSubColArray = [];
                        for (var i = 0; i < diff; i++) {
                            yrSubColArr_new.push(["null", 0]);
                        }
                        var existed = false;
                        var value = 0;
                        for (var k = 0; k < trTypeArr.length; k++) {
                            var type = trTypeArr[k];
                            for (var t = 0; t < yrSubColArr_new.length; t++) {
                                var bitType = yrSubColArr_new[t][0];
                                if (type == bitType) {
                                    value = yrSubColArr_new[t][1];
                                    existed = true;
                                    break;

                                } else {
                                    existed = false;
                                }
                            }
                            if (existed) {
                                var bitArr = [type, value];
                                lasSubColArray.push(bitArr);
                            } else {
                                var bitArr = [type, 0];
                                lasSubColArray.push(bitArr);
                            }
                        }
                        balColArray.push(tempYear);
                        
                        for (i = 0; i < lasSubColArray.length ; i++) {
                            var trType = lasSubColArray[i][0];
                            var trValue = Number(setValuesFormats(Number(lasSubColArray[i][1])));
                            wholeValue += trValue;
                            if (trType == "Imports") {
                                var balance = wholeValue - trValue * 2;
                                if (tradeType != "noneTrade") {
                                    balanceChartTable += '<tr><td>' + year + '</td><td>' + setValuesFormats(Number(balance)) + '</td></tr>';;
                                }
                                balColArray.push(balance);
                                balValueArray.push(balance);
                            }
                        }

                        balDataArray.push(balColArray);
                        balColArray = [];
                        subColumnArray = [];
                        wholeValue = 0;
                        
                        yrSubColArr_new = [];
                        lasSubColArray = [];
                        yrSubColArr_new.push(oneBitArray)
                       
                        


                    } else {
                        balColArray.push(tempYear);
                        
                        for (i = 0; i < yrSubColArr_new.length ; i++) {
                            var trType = yrSubColArr_new[i][0];
                            var trValue = Number(setValuesFormats(Number(yrSubColArr_new[i][1])));
                            wholeValue += trValue;
                            if (trType == "Imports") {
                                var balance = wholeValue - trValue * 2;
                                if (tradeType != "noneTrade") {
                                    balanceChartTable += '<tr><td>' + year + '</td><td>' + setValuesFormats(Number(balance)) + '</td></tr>';;
                                }
                                balColArray.push(balance);
                                balValueArray.push(balance);
                            }
                        }
                        
                        wholeValue = 0;
                        balDataArray.push(balColArray);
                        balColArray = [];
                        subColumnArray = [];
                        yrSubColArr_new = [];
                        lasSubColArray = [];
                        yrSubColArr_new.push(oneBitArray)
                        
                    }


                }
                //tempValue = Number.parseFloat(wholeVal);

                tempYear = year;
                wholeVal = Number(valueTrade);
                
                

            })
            
            balanceChartTable += '</table>';
            var balMin = 0;
            var balMax = 0;
            var maxValueBal = 0;
            var minValueBal
            var yearsB = maxYear - minYear;
            if (yearsB >= 5) {
                rotate = -90;
                Ybal = 1;
                X = 3;
            } else {
                rotate = 0
                Y = -3;
                Ybal = 1;
                X = 0;
            }
            maxValueBal = Math.ceil(Math.max.apply(Math, balValueArray));
            minValueBal = Math.ceil(Math.min.apply(Math, balValueArray));
            if (maxValueBal > 0) {
                balMax = maxValueBal + Math.ceil(maxValueBal / 4.5);
            } else {
                balMax = 0;

            }
            if (minValueBal < 0) {
                balMin = minValueBal + Math.ceil(minValueBal / 4.5);
            } else {
                balMin = 0;

            }


            var yearsArray = [];
            var valueArray = [];
            var title = "Trading Balance";
            for (index = 0; index < balDataArray.length; index++) {
                yearsArray.push(balDataArray[index][0]);

                var balValue = balDataArray[index][1];
                valueArray.push(balValue);


            }
            $('#balanceCanvas').siblings(".dataTable").html('');
            $('#balanceCanvas').siblings(".dataTable").html(balanceChartTable);
            balanceChart = Highcharts.chart('balanceCanvas', {
                chart: {
                    type: 'column',
                    backgroundColor: "rgb(250,250,250)"
                },
                title: {
                    text: "----",
                    style: { "color": "#fff", "line-height": "0.01", "font-size": "0.3em" }
                }, exporting: {
                    enabled: false
                },
                tooltip: {
                    headerFormat: '{point.x}<br/>',
                    pointFormat: '{series.name}: {point.y:.1f}'
                },
                credits: {
                    enabled: false
                },
                xAxis: {
                    alternateGridColor: 'rgba(0, 0, 0, .1)',
                    categories: yearsArray,
                    labels: {
                        style: { "font-size": "0.8em" }
                    }
                },
                yAxis: {
                    labels: {
                        enabled: false
                    },
                    //min: balMin,
                    //max: balMax,
                    title: {
                        enabled: false
                    },
                    stackLabels: {
                        enabled: true,
                        reversed: true,
                        style: { "font-weight": "lighter", "color": "#000", "font-size": "0.8em", "text-shadow": "0px" },
                        rotation: rotate,
                        x: X,
                        step: 1,
                        //y: Ybal,
                        //formatter: function () {
                        //    return setValuesFormats(this.total);
                        //}

                    }
                },
                legend: {
                    enabled: false
                },
                plotOptions: {
                    column: {
                        stacking: 'normal',
                        dataLabels: {
                            enabled: false,
                            color: (Highcharts.theme && Highcharts.theme.dataLabelsColor) || 'white'
                        }
                    }
                },
                series: [{
                    name: title,
                    data: valueArray,
                    color: '#1dd1a1',
                    negativeColor: '#ee5253'

                }]
            });
            return;
           
        },
        failure: function (response) {
        },
        //async: false,
        //cache: false
    });
   
    
}
var mapChartTable;
function drawMap(filterArray) {
    
    var colors = [];
    $(".tradeColorContainer").children(".trColor").each(function () {
        colors.push($(this).css("background-color"));
    });
    mapChartTable = '';
    var mapSelectedYear = $("#slcYear option:selected").val();
    var data = [];
    var dataMap = { filter: filterArray,  year: mapSelectedYear };
    mapChartTable += '<table><tr><th>Country ID</th><th>Trading Value</th></tr>';
    $.ajax({
        type: "POST",
        url: "Server.aspx/getCountriesMap",
        data: JSON.stringify(dataMap),
        contentType: "application/json; charset=utf-8",
        dataType: "json",
        success: function (response) {
            var dataBYY = response.d;
            var query = "";
            $(dataBYY).each(function () {
                 
                
                var id = this.id;
                var val = Number(setValuesFormats(Number(this.value)));
                if (val == 0 || val < 0) {
                    val = 0.0000000000000000001;
                }
                mapChartTable += '<tr><td>' + id + '</td><td>' + val + '</td></tr>';
                var columnArr = [id, val];
                data.push(columnArr);
            })
            mapChartTable += '</table>';
           
            $('#map').siblings(".dataTable").html('');
            $('#map').siblings(".dataTable").html(mapChartTable);
            var mapHeight = Number($(".chartsContainerWide").innerHeight()) - Number($(".chartHeader").innerHeight()) - 10;

            $.getJSON("/JSLibrary/Countries.geo.json", function (geojson) {
                
                mapChart = Highcharts.mapChart('map', {
                    chart: {
                        map: geojson,
                        height: mapHeight,
                        backgroundColor: "rgb(250,250,250)",

                    }, legend: {
                        enabled: false
                    }, exporting: {
                        enabled: false
                    },

                    tooltip: {
                        pointFormat: '{point.properties.CNT_Countr} <br />Year: ' + mapSelectedYear + '<br />Trading Value :<b>{point.value}</b>',

                    },
                    credits: {
                        enabled: false
                    }, title: {
                        text: "UAE Foreign Trade By Country",
                        style: { "display": "none" }

                    },

                    mapNavigation: {
                        enabled: true,
                        buttonOptions: {
                            theme: {
                                visibility:"hidden"
                            }
                        }
                    },

                    colorAxis: {
                        enabled: false
                    },

                    colorAxis: {

                        type: 'logarithmic',
                        minColor: '#FFC312',
                        maxColor: '#EE5A24',
                        stops: [
                            [0, '#FFC312'],
                            [0.65, '#F79F1F'],
                            [1, '#EE5A24']
                        ]
                    },

                    series: [{
                        data: data,
                        keys: ['CNT_ID', 'value'],
                        joinBy: 'CNT_ID',
                        cursor: "pointer",
                        name: 'Trading Value',
                        borderColor: '#aaa',
                        borderWidth: 0.1,
                        point: {
                            events: {
                                click: function (e) {
                                    var countryId = this.properties.CNT_ID;

                                    $("#countryIn").val(countryId);
                                    filterArray = getFilter();

                                    $(document).find("#loader").css('visibility', 'visible');
                                    drawMap(filterArray)

                                    drawTopCountriesChart(filterArray, colors);

                                    drawSliderCharts(filterArray, colors);
                                    drawBalanceChart(filterArray, colors);

                                    drawGrowthTable(filterArray);
                                    reloadLists(countryId);

                                    $(document).find("#loader").css('visibility', 'hidden');

                                }
                            }
                        },
                        //},
                        //events: {
                        //    click: function (e) {
                        //        e.point.zoomTo();
                        //    }
                        //},
                        states: {
                            hover: {
                                color: 'rgba(192, 57, 43,1.0)'
                            }
                        },
                        dataLabels: {
                            enabled: false,
                            format: '{point.properties.CNT_ID}'
                        }
                    }]
                });

                var series = mapChart.series[0].points;

                var pointsArr = [];
                for (var i = 0; i < series.length; i++) {
                    if (series[i].isNull == false) {
                        pointsArr.push(series[i]);
                    }
                }



                var midxarr = [];
                var midyarr = [];
                for (var i = 0; i < pointsArr.length; i++) {
                    if (pointsArr[i]._midX != undefined && pointsArr[i]._midX != "-Infinity" && pointsArr[i]._midX != "+Infinity") {
                        midxarr.push(pointsArr[i]._midX);
                    }

                }

                for (var i = 0; i < pointsArr.length; i++) {
                    if (pointsArr[i]._midY != undefined && pointsArr[i]._midY != "-Infinity" && pointsArr[i]._midY != "+Infinity") {
                        midyarr.push(pointsArr[i]._midY);
                    }
                }
                midxarr.sort();
                midyarr.sort();
                midxIndex = Math.floor((midxarr.length) / 2);
                midyIndex = Math.floor((midyarr.length) / 2);
                var midXOfAll = midxarr[midxIndex];
                var midYOfAll = midyarr[midyIndex];

                var points = pointsArr.length;
                if (points > 200) {
                    zoomLev = 1;
                }
                if (points < 100 && points >= 50) {
                    zoomLev = 0.5;
                }
                if (points < 50 && points >= 20) {
                    zoomLev = 0.5;
                }
                if (points < 20 && points >= 10) {
                    zoomLev = 0.4;
                }
                if (points < 10 && points > 1) {
                    zoomLev = 0.3;
                }
                if (points <= 1) {
                    zoomLev = 0.2;
                }
                mapChart.mapZoom(zoomLev, midXOfAll, midYOfAll);
            });

            return;
           
        },
        failure: function (response) {
        },
        //async: false,
        //cache: false
    });
    
}


 

